function solve(landStartTime, landDuration, waterStartTime, waterDuration) {
    // Generate all possible combinations of one land and one water attraction
    const n = landStartTime.length;
    const m = waterStartTime.length;
    let minEndTime = Infinity;

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            // Case 1: Land first, then water
            let landEnd = Math.max(landStartTime[i], landStartTime[i] + landDuration[i]);
            let waterStart = Math.max(landEnd, waterStartTime[j]);
            let waterEnd = waterStart + waterDuration[j];
            minEndTime = Math.min(minEndTime, waterEnd);

            // Case 2: Water first, then land
            let waterEnd2 = Math.max(waterStartTime[j], waterStartTime[j] + waterDuration[j]);
            let landStart = Math.max(waterEnd2, landStartTime[i]);
            let landEnd2 = landStart + landDuration[i];
            minEndTime = Math.min(minEndTime, landEnd2);
        }
    }

    return minEndTime;
}
